css:
/* ===== 字体 ===== */
@font-face {
    font-family: "Jing Hua ";
    src: url("https://files.catbox.moe/138mza.ttf") format("truetype");
}
body, #nonQRFormItems textarea,.mes_text pre code, .mes_reasoning pre code,input, select, button {
    font-family: "Jing Hua ", sans-serif;
}

code {
    background-color: rgb(191 191 191 / 49%);
    color: rgb(89 89 89);
}
/* 斜体 */
.mes_text em {
    text-decoration: underline;
    text-decoration-color: #8d8d8dc2;
    text-decoration-thickness: 2px;
}
/* 引用 */
.mes_text q {
    background: linear-gradient(135deg, rgb(96 96 96 / 30%), rgb(148 146 146 / 0%));
    padding: 0px 0px;
    display: inline;
    box-decoration-break: clone;
    -webkit-box-decoration-break: clone;
}
/* 代码块 */
.mes_text pre, .mes_reasoning pre {
    background-color: #cecece;
    padding: 20px 5px 10px;
    border-radius: 5PX;
    margin: 15px 0 10px;
    position: relative;
    box-sizing: border-box;
    box-shadow: 0 4px 12px rgb(73 73 73 / 50%), inset 0 0 0 1px rgba(255, 255, 255, 0.25), inset 0 0 16px rgba(255, 255, 255, 0.1) !important;
    border: 2px solid rgb(167 163 163);
}
.mes_text pre::after,
.mes_reasoning pre::after {
  content: "下一站：ONE NIGHT";/*☁️*/
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
}

.mes_text pre code, .mes_reasoning pre code {
    background-color: #e2e2e2;
    color: #464646;
    box-sizing: border-box;
    border-radius: 0;
}

#chat > div > div.mes_block > div.mes_text > pre > code > i {
  font-size: 0; /* 隐藏原图标内容 */
  display: inline-block;
  width: 20px;
  height: 20px;
  background: url('https://i.postimg.cc/tTqy4b5P/IMG-2660.png') no-repeat center;
  background-size: contain;
  vertical-align: middle;
  margin:0;
}

/*引用块*/
.mes_text blockquote, .mes_reasoning blockquote {
    background-color: rgb(161 153 143 / 10%);
    border-radius: 5px;
}
/* ===== 动画 ===== */
/* 移除原始伪元素 */
#load-spinner ,#load-spinner::before{
   animation: none;
   content: "";
}

/* 创建新的自定义加载动画 */
#load-spinner::after {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 60px;
    height: 60px;
    background: url('https://i.postimg.cc/hjGn1Sk6/IMG-2639.png') center/contain no-repeat;
    transform: translate(-50%, -50%);
    z-index: 1000;
    /* 添加左右旋转摇晃动画 */
    animation: rotate-shake 3s ease-in-out infinite;
}

/* 闪烁动画 */
@keyframes blink {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}

/* 隐藏原有旋转动画 */
@keyframes custom-spin {
    display: none;
}
/* ===== 思维块美化 ===== */
.mes_reasoning_header {
    cursor: pointer;
    position: relative;
    left: 50%;
    transform: translate(-50%, -50%);
    user-select: none;
    margin: 5px;
    padding: 2px 8px;
    padding-right: calc(0.7em + 14px);
    background-color: #ffffff38;
    border: 2px dashed #9a9a9a;
    border-radius: 20px;
    font-size: calc(var(--mainFontSize) * 0.9);
    color: #545454;
    align-items: baseline;
    font-size: 0 !important;
}

.mes_reasoning_header::before {
    content: "˚.⊹ 𖦆 𝒪𝒷𝓈𝒸𝓊𝓇𝑒 𝓅𝑜𝑒𝓉𝓇𝓎 𓈒𓏸˚₊"; /* ☁️修改文字内容 */
    font-size: calc(var(--mainFontSize) * 0.9);
    display: inline;
}

.fa-chevron-up:before {
    content: ""; /* 去除原有样式 */
}

.fa-chevron-up::before {
    content: "";
    display: inline-block;
    width: 10px;
    height: 10px;
    background-image: url("https://i.postimg.cc/4NmzmGZS/IMG-2480.png");
    background-size: 10px 10px;
    background-repeat: no-repeat;
}

/* ====== 气泡 ====== */


.mes_block {
    padding-left: 0;
}

body.bubblechat .mes, body.bubblechat .mes[is_user="true"] {
    padding: 13px;
    border-radius: 0px;
    padding-bottom: 30px;
    border: none;
    max-width: 95%;
    margin: 300px auto 25px auto;
    position: relative;
    background-color: rgb(255 255 255 / 50%) !important;
    backdrop-filter: blur(20px) saturate(200%) !important;
    -webkit-backdrop-filter: blur(20px) saturate(200%) !important;
    box-shadow: 0 4px 12px rgb(84 84 84 / 50%), inset 0 0 0 1px rgba(255, 255, 255, 0.25), inset 0 0 16px rgba(255, 255, 255, 0.1) !important;
}

.mes {
    padding: 13px;
    border-radius: 0px;
    padding-bottom: 30px;
    border: none;
    max-width: 95%;
    margin: 300px auto 25px auto;
    position: relative;
    background-color: rgb(255 255 255 / 50%) !important;
    backdrop-filter: blur(20px) saturate(200%) !important;
    -webkit-backdrop-filter: blur(20px) saturate(200%) !important;
    box-shadow: 0 4px 12px rgb(84 84 84 / 50%), inset 0 0 0 1px rgba(255, 255, 255, 0.25), inset 0 0 16px rgba(255, 255, 255, 0.1) !important;
}

.mes::before {
    content: "";
    position: absolute;
    top: -310px; /* 图片高度 */
    width: 100%;
    height: 342px;
    left: 50%;
    transform: translateX(-50%);
    background-image: url("https://i.postimg.cc/prH7kJ9b/IMG-2659.png");
    background-size: 570px 342px; 
    background-repeat: repeat;
    background-position: center;
    z-index: 3;
    pointer-events: none; /* 防止影响点击 */

}

/* 为所有气泡添加底部文字 */
.mes::after {
    content: "⭑₊ 想念变成空气在叹息୨୧‧₊˚";/*☁️*/
    position: absolute;
    bottom: 5px; 
    left: 50%;
    transform: translateX(-50%);
    background-image: url("https://i.postimg.cc/9FmD43xW/IMG-2665.png");
    background-size: 330px 44px; 
    background-repeat: repeat;
    background-position: center;
    z-index: 1;
}

/* 翻页 */
.swipe_left {
    left: 5px;
}

.fa-chevron-right:before {
    content: "";
    display: inline-block;
    width: 30px;
    height: 30px;
    background-image: url("https://i.postimg.cc/zBz5GNjh/IMG-2661.png");
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    vertical-align: middle;
}

.fa-chevron-left:before {
    content: "";
    display: inline-block;
    width: 30px;
    height: 30px;
    background-image: url("https://i.postimg.cc/zBz5GNjh/IMG-2661.png");
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    vertical-align: middle;
}

/* 文本 */
.mes_text {
    padding-left: 5px;
    padding-top: 5px;
    padding-bottom: 5px;
    padding-right: 5px;
}

.fa-pencil-alt:before, .fa-pencil:before ,.fa-ellipsis-h:before, .fa-ellipsis:before {
 content: "";
  display: inline-block;
  width: 20px;
  height: 20px;
  background: url('https://i.postimg.cc/zBz5GNjh/IMG-2661.png') no-repeat center;
  background-size: contain;
  vertical-align: middle;
}

/*幽灵*/
.fa-ghost:before {
  content: "";
  display: inline-block;
  width: 25px;
  height: 25px;
  background: url('https://i.postimg.cc/vH4Kqhyx/IMG-2622.png') no-repeat center;
  background-size: contain;
  vertical-align: middle;
}

.reasoning_edit_textarea, .edit_textarea {
    background-color: rgb(107 107 107 / 23%);
}
/* ====== 头像 ====== */
.mesAvatarWrapper {
    width: 500px;
    height: 210px;
    object-fit: cover;
    display: block;
    position: absolute;
    left: 50%;
    transform: translate(-50%);
    top: -240px; /* 微调位置使头像底部高于消息15px */
}

.mesAvatarWrapper .avatar img {
width: 1000%;
height: 420%;
object-fit: cover;
border-radius: inherit;
}
/* 覆盖图片 */
.mesAvatarWrapper::after {
    content: ""; /* 确保伪元素有内容 */
    position: absolute;
    left: 50%;
    top: 110px; /* 添加垂直居中定位 */
    transform: translate(-50%, -50%); /* 同时调整水平和垂直偏移 */
    width: 570px;
    height: 342px;
    background-image: url("https://i.postimg.cc/hjx695t3/IMG-2658.png");
    background-size: cover;
    background-position: center;
    z-index: 2; /* 覆盖头像 */
    pointer-events: none; /* 防止影响点击 */
}


.mes .mes_timer {
    cursor: default;
    opacity: 0.7;
    font-size: 0.7em;
    font-weight: 600;
    text-align: right;
    position: absolute;
    left: 10px;
    white-space: nowrap; /* 防止换行 */
    top: 175px;
    z-index: 10;
    color: rgb(196, 153,170);
}


.mes .mesIDDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: 0.7em;
    font-weight: 600;
    text-align: right;
    position: absolute;
    white-space: nowrap; /* 防止换行 */
    left: 60px;
    top: 175px;    
    z-index: 10;
    color: rgb(196, 153,170);
}


.mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: 0.7em;
    font-weight: 600;
    text-align: right;
    position: absolute;
    left: 100px; 
    text-align: right; /* 右对齐 */
    white-space: nowrap; /* 防止换行 */
    top: 175px;
    z-index: 10;
    color: rgb(196, 153,170);
}

/* 时间戳位置 */
.mes .timestamp {
    font-size: 10px;
    font-weight: 600;
    position: absolute; /* 绝对定位 */
    left: calc(50% - 240px); 
    top: -50px; /* Y轴偏移-40px */
    text-align: right; /* 右对齐 */
    white-space: nowrap; /* 防止换行 */
    z-index: 10; /* 确保显示在最前面 */
    opacity: 0.7; /* 保持原有透明度 */
    color: rgb(196, 153,170);
}


.mes .name_text {
    font-size: 0.7em;
    position: absolute; /* 绝对定位 */
    left: calc(50% - 240px); /* 中心向左偏移150px */
    top: -80px; /* Y轴向上偏移165px */
    text-align: center; 
    white-space: nowrap; /* 防止换行 */
    z-index: 10; /* 确保显示在最前面 */
    cursor: default;
    opacity: 0.7;
    font-weight: 600;
    color: rgb(196, 153,170);
}

.mes_block {
  transform: none !important;
}


/* ===== 底部输入栏 ===== */
#qr--bar {
    outline: none;
    margin: 0;
    transition: 0.3s;
    opacity: 0.7;
    display: flex;
    align-items: center;
    justify-content: center;
    top:5px ;
    width: 100%;
    max-width: 100%;
    /* 修改高度为自适应 */
    height: auto;
    /* 设置最大高度并允许垂直滚动 */
    max-height: 30px; /* 保留原始高度作为最大高度 */
    /* 允许水平和垂直方向滚动 */
    overflow: auto; /* 替代原来的overflow-x和overflow-y */
    scrollbar-width: thin;
    scrollbar-color: #888 #f0f0f0;
}

/* 统一滚动条样式 */
#qr--bar::-webkit-scrollbar {
    width: 4px;  /* 垂直滚动条宽度 */
    height: 4px; /* 水平滚动条高度 */
}

#qr--bar::-webkit-scrollbar-track {
    background: #f0f0f0;
}

#qr--bar::-webkit-scrollbar-thumb {
    background-color: #888;
    border-radius: 2px;
}

#send_form {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    width: 100%;
    margin: 0px auto 0px auto; /* 上下边距15px */
    border: 1px solid var(--SmartThemeBorderColor);
    border-radius: 30px; /* 四个角的圆角度数为0 */
}

#nonQRFormItems {
    padding: 5px;
    border: 0;
    position: relative;
    background-position: center;
    display: flex;
    flex-direction: row;
    column-gap: 5px;
    font-size: var(--bottomFormIconSize);
    order: 25;
    width: 100%;
    min-height: 30px;
    align-items: center;
    overflow: hidden;
    border-radius: 30px;
    border: 2px solid #e9e9e9 !important;
    box-shadow: inset 0 2px 4px rgb(170 170 170 / 80%) !important;
    backdrop-filter: blur(var(--SmartThemeBlurStrength));
    position: relative;
}
/* 字体图标容器固定大小 */
#nonQRFormItems .icon-container {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 30px;
    width: 30px; /* 固定宽度 */
    flex-shrink: 0; /* 防止图标被压缩 */
}

#qr--bar > .qr--buttons .qr--button, #qr--popout > .qr--body > .qr--buttons .qr--button{
    transform: scale(0.9);
}


/*停止钮*/
.fa-circle-stop:before,
.fa-stop-circle:before {
  content: ""; /* 移除原图标 */
  display: inline-block;
  width: 20px;
  height: 20px;
  background: url('https://i.postimg.cc/4d3GQJD0/IMG-2640.png') no-repeat center;
  background-size: contain;
  opacity: 1;
  animation: blink 1.5s ease-in-out infinite; /* 改为闪烁动画 */
  transform-origin: center;
}

/* 闪烁动画 */
@keyframes blink {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}

@keyframes rotateShake {
  0%, 100% {
    transform: rotate(0deg);
  }
  25% {
    transform: rotate(-10deg); /* 向左旋转 */
  }
  75% {
    transform: rotate(10deg); /* 向右旋转 */
  }
}

/*小飞机*/
.fa-paper-plane:before {
  content: "";
  display: inline-block;
  width: 20px;
  height: 20px;
  background: url('https://i.postimg.cc/4d3GQJD0/IMG-2640.png') no-repeat center;
  background-size: contain;
  vertical-align: middle;
}


/* ===== 顶部 ===== */

#top-bar {
    margin: 0 auto;
    left: 0;
    right: 0;
    display: inline-block;
    height: 30px; /* 固定高度 */
    position: absolute;
    box-shadow: none;
    opacity:0;
    z-index: 3005;
}

.drawer-toggle .drawer-icon {
    transform-origin: center;
    display: inline-block;
    width: auto;
    height: auto;
}

.drawer-icon.closedIcon {
    opacity: 0;
    transition: all 0.275s;
}

/* 如果原有内容是通过伪元素实现的 */
.drawer-toggle .drawer-icon:before {
    content: "" !important;
    background: url('https://i.postimg.cc/Dzdnh0q1/IMG-2662.png') no-repeat center !important;
    background-size: contain !important;
    display: inline-block;
    width: 25px;
    height: 25px;
}
/* ===== UI ===== */
#extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header, #user-settings-block h4, .standoutHeader {
    background: -webkit-linear-gradient(right, #c1c1c100, #bebebe);
    opacity: 0.7;
    margin-bottom: 4px;
    padding: 2px 5px 2px 5px;
    border: 2px solid rgb(166 166 166);
    position: relative;
    border-radius: 0px;
    box-shadow: none !important;
}

/* 滑块 */

input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    margin: 0;
    padding: 0;
    width: 100%;
    height: 5px;
    background: var(--white50a);
    border-radius: 15px;
    background-size: 70% 100%;
    background-repeat: no-repeat;
    cursor: ew-resize;
    /* 移除可能的阴影 */
    box-shadow: none;
}

/* Webkit浏览器滑块样式 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 20px;
    height: 20px;
    background: url('https://i.postimg.cc/8C4DvF07/IMG-2641.png') center/contain no-repeat;
    cursor: pointer;
    border: none;
    /* 移除滑块阴影 */
    box-shadow: none;
}

/* Firefox浏览器滑块样式 */
input[type="range"]::-moz-range-thumb {
    width: 20px;
    height: 20px;
    background: url('https://i.postimg.cc/8C4DvF07/IMG-2641.png') center/contain no-repeat;
    cursor: pointer;
    border: none;
    /* 移除滑块阴影 */
    box-shadow: none;
}

/* 针对IE浏览器（如果需要） */
input[type="range"]::-ms-thumb {
    box-shadow: none;
}

/* 图标 */

.fa-bars:before, .fa-navicon:before {
    content: ""; /* 移除原有图标 */
    display: inline-block;
    width: 20px;
    height: 20px;
    background: url('https://i.postimg.cc/hjGn1Sk6/IMG-2639.png') center/contain no-repeat;
    vertical-align: middle;
}

.fa-magic-wand-sparkles:before, .fa-wand-magic-sparkles:before {
    content: ""; /* 移除原有图标 */
    display: inline-block;
    width: 20px;
    height: 20px;
    background: url('https://i.postimg.cc/8C4DvF07/IMG-2641.png') center/contain no-repeat;
    vertical-align: middle;
}

.drawer-content select {
    background-color: #bbbbbb2b;
    border-radius: 3px;
}

.neo-range-input, #completion_prompt_manager #completion_prompt_manager_list {
    background-color: #c9c9c924;
}

textarea, .textarea_compact, .range-block-counter input, .text_pole {
    background-color: #e4e4e4;
    color: rgb(83 83 83);
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: #b7b7b7;
}

#completion_prompt_manager .completion_prompt_manager_header div {
    color: #918a86;
}

#completion_prompt_manager .completion_prompt_manager_header_advanced span {
    filter:none;
}

/*预设正则空间预留*/
#global_scripts_block ,#scoped_scripts_block ,#completion_prompt_manager_list{
    padding-right: 30px;
}

/*热切换*/
#HotSwapWrapper {
    position: relative;
    overflow-x: auto;
    scrollbar-width: thin; /* Firefox */
    scrollbar-color: rgba(255, 182, 193, 0.3) 
}

#HotSwapWrapper::-webkit-scrollbar {
    height: 1px; /* 设置滚动条高度为3px */
}

#HotSwapWrapper::-webkit-scrollbar-track {
    background: transparent; /* 滚动条轨道透明 */
}

#HotSwapWrapper::-webkit-scrollbar-thumb {
    scrollbar-color: rgba(255, 182, 193, 0.3) 
    border-radius: 0; /* 无圆角 */
    border: none; /* 无边框 */
}

#HotSwapWrapper > * {
    flex-shrink: 0;
}



/* --- 默认隐藏 QR 按钮容器，并设置平滑过渡 --- */
.qr--buttons {
  opacity: 0;
  visibility: hidden;
  max-height: 0;
  transform: translateY(20px);
  pointer-events: none;
  transition:
    opacity 0.3s ease-in-out,
    visibility 0.3s ease-in-out,
    max-height 0.5s ease,
    transform 0.5s ease;
}

/* --- 输入框获得焦点时显示 QR 区域 --- */
#send_form:focus-within .qr--buttons {
  opacity: 1;
  visibility: visible;
  max-height: 45px;
  transform: translateY(0);
  pointer-events: auto;
}

/* --- 新增：修复空白弹窗，仅隐藏空白背景，不影响点击 --- */
#qr--bar {
  opacity: 0;
  visibility: hidden;
  max-height: 0;
  pointer-events: none;
  transition:
    opacity 0.3s ease-in-out,
    visibility 0.3s ease-in-out,
    max-height 0.3s ease;
}

/* --- 当输入框聚焦或激活时才显示 QR bar 内容 --- */
#send_form:focus-within #qr--bar,
.qr--buttons.active #qr--bar {
  opacity: 1;
  visibility: visible;
  max-height: 45px;
  pointer-events: auto;
}



/* 全局滑动条样式 */
::-webkit-scrollbar {
    width: 1px; /* 滑动条宽度 */
    height: 1px; /* 水平滑动条高度 */
}

::-webkit-scrollbar-track {
    background: transparent; /* 轨道背景透明 */
}

::-webkit-scrollbar-thumb {
    background: rgba(197,197, 197, 0.5); /* 半透明浅粉色 */
    border-radius: 0; /* 无圆角 */
}

::-webkit-scrollbar-thumb:hover {
    background: rgba(197,197, 197, 0.5); /* 鼠标悬停时稍微加深 */
}

/* Firefox 浏览器 */
* {
    scrollbar-width: thin; /* 细滚动条 */
    scrollbar-color: rgba(197,197, 197, 0.5) transparent; /* 滑块半透明浅粉色，轨道透明 */
}


.options-content, .list-group {
    overflow: hidden;
    display: block;
    border: 1px solid var(--SmartThemeBorderColor);
    border-radius: 10px;
    z-index: 2000;
    font-size: calc(var(--mainFontSize) * 1.1);
    position: relative; /* 为伪元素定位做准备 */
}

/* 毛玻璃效果伪元素 */
.options-content::before, .list-group::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    z-index: -1; /* 放在内容后面 */
    border-radius: 10px;
